#include <stdio.h>

int main() {
    int broj_bodova;
    
    printf("Unesite broj bodova: ");
    scanf("%d", &broj_bodova);
    
    if (broj_bodova < 0) {
        printf("Neispravan broj bodova.");
    } else if (broj_bodova <= 54) {
        printf("Ocjena: 5");
    } else if (broj_bodova <= 64) {
        printf("Ocjena: 6");
    } else if (broj_bodova <= 74) {
        printf("Ocjena: 7");
    } else if (broj_bodova <= 84) {
        printf("Ocjena: 8");
    } else if (broj_bodova <= 94) {
        printf("Ocjena: 9");
    } else {
        printf("Ocjena: 10");
    }
    
    return 0;
}
